parameters.jsCode:
const inputData = $input.item.json || {};
const batchSize = parseInt(inputData.batchSize) || 5000;

// Get GSC Property type from Airtable56 node
const gscPropertyType = 'Domain';

console.log('GSC Property:   ',gscPropertyType)

// Format date as YYYY-MM-DD
function formatDate(date) {
  const year = date.getFullYear();
  const month = `${date.getMonth() + 1}`.padStart(2, '0');
  const day = `${date.getDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// GSC allows up to 16 months of data
const endDate = new Date();
endDate.setDate(endDate.getDate() - 1); // Yesterday
const startDate = new Date(endDate);
startDate.setMonth(startDate.getMonth() - 16);

// Enhanced GSC URL encoder with property type support
function encodeGscUrl(url, propertyType = 'Domain') {
  try {
    // Ensure URL has protocol
    const urlWithProtocol = url.startsWith('http://') || url.startsWith('https://')
      ? url
      : 'https://' + url;

    // For URL property type, return the full URL encoded
    if (propertyType.toLowerCase() === 'url prefix') {
      // Parse URL to get just protocol + hostname (no path/slug)
      const parsed = new URL(urlWithProtocol);
      const baseUrl = `${parsed.protocol}//${parsed.hostname}`;

      // Encode URL with dots also encoded (as required by GSC API)
      const fullyEncodedUrl = encodeURIComponent(baseUrl).replace(/\./g, '%2E');

      return {
        encodedSiteUrl: fullyEncodedUrl,
        fullUrl: urlWithProtocol,
        propertyType: 'URL Prefix',
        rawFormat: baseUrl
      };
    }

    // For domain property type, use sc-domain format
    const parsed = new URL(urlWithProtocol);
    let hostname = parsed.hostname;

    // Remove 'www.' prefix if present to get the base domain
    if (hostname.startsWith('www.')) {
      hostname = hostname.substring(4);
    }

    // Create the sc-domain format
    const scDomain = `sc-domain:${hostname}`;

    return {
      encodedSiteUrl: encodeURIComponent(scDomain),
      fullUrl: urlWithProtocol,
      propertyType: 'Domain',
      rawFormat: scDomain
    };

  } catch (error) {
    // Fallback for malformed URLs
    console.error('URL parsing failed for:', url, error);

    // For URL property type with parsing error
    if (propertyType.toLowerCase() === 'url prefix') {
      const urlWithProtocol = url.startsWith('http://') || url.startsWith('https://')
        ? url
        : 'https://' + url;

      // Manual parsing to get just protocol + hostname (no path/slug)
      const protocolMatch = urlWithProtocol.match(/^https?:\/\//);
      const protocol = protocolMatch ? protocolMatch[0] : 'https://';

      // Remove protocol to get the rest
      let remainder = urlWithProtocol.replace(/^https?:\/\//, '');

      // Get hostname (everything before first / or : for port)
      let hostname = remainder.split('/')[0].split(':')[0];

      const baseUrl = protocol + hostname;

      // Encode URL with dots also encoded (as required by GSC API)
      const fullyEncodedUrl = encodeURIComponent(baseUrl).replace(/\./g, '%2E');

      return {
        encodedSiteUrl: fullyEncodedUrl,
        fullUrl: urlWithProtocol,
        propertyType: 'URL Prefix',
        rawFormat: baseUrl
      };
    }

    // For domain property type with parsing error - manual extraction
    let domain = url;

    // Remove protocol if present
    domain = domain.replace(/^https?:\/\//, '');

    // Remove path (everything after first /)
    domain = domain.split('/')[0];

    // Remove www. if present
    if (domain.startsWith('www.')) {
      domain = domain.substring(4);
    }

    // Remove port if present
    domain = domain.split(':')[0];

    const scDomain = `sc-domain:${domain}`;

    return {
      encodedSiteUrl: encodeURIComponent(scDomain),
      fullUrl: url.startsWith('http') ? url : 'https://' + url,
      propertyType: 'Domain',
      rawFormat: scDomain
    };
  }
}

// Report config with property type included
const reportConfig = {
  startDate: formatDate(startDate),
  endDate: formatDate(endDate),
  batchSize,
  reportName: `GSC Keywords: ${formatDate(startDate)} to ${formatDate(endDate)}`,
  gscPropertyType: gscPropertyType
};

// Handle the actual input structure
let outputItems = [];

// Check if inputData.output exists and has links
if (inputData.output && inputData.output.links && Array.isArray(inputData.output.links)) {
  outputItems = inputData.output.links;
} else if (Array.isArray(inputData.output)) {
  // Handle legacy format if needed
  if (inputData.output.length > 0 && inputData.output[0].output) {
    // Case: [{ output: [...] }]
    outputItems = inputData.output[0].output;
  } else {
    // Case: [{ url, target }, ...]
    outputItems = inputData.output;
  }
}

// Validate that we have URLs to process
if (!outputItems || outputItems.length === 0) {
  throw new Error('No URLs provided for processing');
}

return outputItems.map(entry => {
  const url = entry.url;
  const target = entry.target;

  // Use the property type from Airtable to encode correctly
  const encoded = encodeGscUrl(url, gscPropertyType);

  return {
    json: {
      reportConfig,
      urlToProcess: {
        url,
        encodedUrl: encoded,
        processed: false,
        batchStart: 0,
        hasMoreData: true
      },
      target,
      gscPropertyType: gscPropertyType,
      result: {},
      previousPeriodResult: {}
    }
  };
});

/**
 * Error handling node
 */
const response = $input.item.json;
const statusCode = response.error.context?.statusCode || response.error.status || 0; // Safe access with fallbacks
const statusMessage = response.error.message || 'Unknown error';
const errorDescription = response.error.description || 'No description available';

return {
  json: {
    error: true,
    statusCode,
    message: statusMessage,
    description: errorDescription,
    details: `Failed to fetch data from Google Search Console API. Error ${statusCode}: ${statusMessage}. ${errorDescription}`
    //requestParams: $node["Date Range Calculator1"].json
  }
};

