    domain = domain.split(':')[0];

    const scDomain = `sc-domain:${domain}`;

    return {
      encodedSiteUrl: encodeURIComponent(scDomain),
      fullUrl: url.startsWith('http') ? url : 'https://' + url,
      propertyType: 'Domain',
      rawFormat: scDomain
    };
  }
}

// Report config with property type included
const reportConfig = {
  startDate: formatDate(startDate),
  endDate: formatDate(endDate),
  batchSize,
  reportName: `GSC Keywords: ${formatDate(startDate)} to ${formatDate(endDate)}`,
  gscPropertyType: gscPropertyType
};

// Handle the actual input structure
let outputItems = [];

// Check if inputData.output exists and has links
if (inputData.output && inputData.output.links && Array.isArray(inputData.output.links)) {
  outputItems = inputData.output.links;
} else if (Array.isArray(inputData.output)) {
  // Handle legacy format if needed
  if (inputData.output.length > 0 && inputData.output[0].output) {
    // Case: [{ output: [...] }]
    outputItems = inputData.output[0].output;
  } else {
    // Case: [{ url, target }, ...]
    outputItems = inputData.output;
  }
}

// Validate that we have URLs to process
if (!outputItems || outputItems.length === 0) {
  throw new Error('No URLs provided for processing');
}

return outputItems.map(entry => {
  const url = entry.url;
  const target = entry.target;

  // Use the property type from Airtable to encode correctly
  const encoded = encodeGscUrl(url, gscPropertyType);

  return {
    json: {
      reportConfig,
      urlToProcess: {
        url,
        encodedUrl: encoded,
        processed: false,
        batchStart: 0,
        hasMoreData: true
      },
      target,
      gscPropertyType: gscPropertyType,
      result: {},
      previousPeriodResult: {}
    }
  };
});

/**
 * N8N Function Node to process Google Search Console data
 * Returns top entries by clicks and impressions with target and URL included
 */

// Get the raw data from GSC API Request node
let inputData;
try {
  const response = $input.item.json;

  if (response.body) {
    inputData = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
  } else {
    inputData = response;
  }
} catch (error) {
  return {
    json: {
      error: "Failed to parse input data",
      details: error.message
    }
  };
}

// Process the rows from the data
const rows = inputData.rows || [];
const contextInput = $input.item.json || {};
const reportConfig = contextInput.reportConfig || {};
// const target = $('Loop Over Items6').item.json.target || "";
const url = $('Loop Over Items6').item.json.urlToProcess.url || "";

if (!rows.length) {
  return {
    json: {
      message: "No data found in the response",
      reportPeriod: reportConfig.reportType,
      dateRange: {
        startDate: reportConfig.startDate,
        endDate: reportConfig.endDate
      },
      url,
      //target,
      topByClicks: [],
      topByImpressions: []
    }
  };
}

// Function to format dimension values for display
function formatDimensions(keys, dimensions) {
  const result = {};
  keys.forEach((key, index) => {
    const dimensionName = dimensions && dimensions[index] ? dimensions[index] : `dimension${index+1}`;
    result[dimensionName] = key;
  });
  return result;
}

const dimensions = ["query"];

const processedRows = rows.map(item => ({
  dimensions: formatDimensions(item.keys, dimensions),
  metrics: {
    clicks: item.clicks,
    impressions: item.impressions,
    ctr: (item.ctr * 100).toFixed(2) + '%',
    position: item.position.toFixed(2)
  }
}));

const topItemsCount = 3; // Changed to top 3

const topByClicks = [...processedRows]
  .sort((a, b) => b.metrics.clicks - a.metrics.clicks)
  .slice(0, topItemsCount);

const topByImpressions = [...processedRows]
  .sort((a, b) => b.metrics.impressions - a.metrics.impressions)
  .slice(0, topItemsCount);

// // Calculate overall metrics
// const totalClicks = rows.reduce((sum, item) => sum + item.clicks, 0);
// const totalImpressions = rows.reduce((sum, item) => sum + item.impressions, 0);
// const avgCTR = totalImpressions > 0 ? 
//   ((totalClicks / totalImpressions) * 100).toFixed(2) + '%' : 
//   '0.00%';
// const avgPosition = rows.length > 0 ? 
//   (rows.reduce((sum, item) => sum + item.position, 0) / rows.length).toFixed(2) : 
//   '0.00';

// Return the complete results with url and target
return {
  json: {
    result: {
    url,
    //target,
    topByClicks,
    topByImpressions
  }
 }
};

/**
 * Error handling node
 */
const response = $input.item.json;
const statusCode = response.error.context?.statusCode || response.error.status || 0; // Safe access with fallbacks
const statusMessage = response.error.message || 'Unknown error';
const errorDescription = response.error.description || 'No description available';

return {
  json: {
    error: true,
    statusCode,
    message: statusMessage,
    description: errorDescription,
    details: `Failed to fetch data from Google Search Console API. Error ${statusCode}: ${statusMessage}. ${errorDescription}`
    //requestParams: $node["Date Range Calculator1"].json
  }
};

