const inputData = $input.all();
const hostName = $('Search records').first().json.Url;

// Extract URLs from the input data and combine with hostname
const urls = inputData.map(item => {
  const slug = item.json["Custom Blog Url"];

  // Ensure hostname doesn't end with slash and slug doesn't start with slash
  const cleanHostName = hostName.replace(/\/$/, '');
  const cleanSlug = slug.replace(/^\//, '');

  // Combine hostname and slug
  return `${cleanHostName}/${cleanSlug}`;
});

// Create the output structure
const result = [
  {
    "reportType": "Monthly",
    "urls": urls
  }
];

// Return the transformed data
return result;

// Get input data
const [current, previous] = $input.all();

// Helper function to extract report config from the first available row
function getReportConfig(data) {
  if (data && data.json) {
    const dataKey = Object.keys(data.json)[0]; // Get first key (current data, previous data, etc.)
    const rows = data.json[dataKey];
    if (rows && rows.length > 0 && rows[0][0] && rows[0][0].reportConfig) {
      return rows[0][0].reportConfig;
    }
  }
  return null;
}

// Get report configuration
const reportConfig = getReportConfig(current) || getReportConfig(previous);

// Determine report type and period labels
let reportType = 'Report';
let currentLabel = 'Current Period';
let previousLabel = 'Previous Period';

if (reportConfig) {
  const configReportType = reportConfig.reportType.toLowerCase();

  if (configReportType.includes('monthly')) {
    reportType = 'Monthly Report';
    currentLabel = 'Current Month';
    previousLabel = 'Previous Month';
  } else if (configReportType.includes('weekly')) {
    reportType = 'Weekly Report';
    currentLabel = 'Current Week';
    previousLabel = 'Previous Week';
  } else if (configReportType.includes('quarterly')) {
    reportType = 'Quarterly Report';
    currentLabel = 'Current Quarter';
    previousLabel = 'Previous Quarter';
  } else if (configReportType.includes('yearly') || configReportType.includes('annual')) {
    reportType = 'Annual Report';
    currentLabel = 'Current Year';
    previousLabel = 'Previous Year';
  } else if (configReportType.includes('daily')) {
    reportType = 'Daily Report';
    currentLabel = 'Current Day';
    previousLabel = 'Previous Day';
  }
}

// Helper to format rows as Markdown table
function toMarkdownTable(rows) {
  if (!rows || !rows.length) return 'No data available';

  const header = '| Page URL | Clicks | Impressions | CTR | Avg Position |\n|---|---|---|---|---|';
  const body = rows.map(rowArr => {
    const row = rowArr[0];
    const url = row.keys[0];
    // Extract page name from URL for better readability
    const pageName = url.split('/').pop().replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
    return `| [${pageName}](${url}) | ${row.clicks} | ${row.impressions} | ${(row.ctr*100).toFixed(2)}% | ${row.position.toFixed(1)} |`;
  }).join('\n');

  return `${header}\n${body}`;
}

// Calculate totals for summary
function calculateTotals(rows) {
  if (!rows || !rows.length) return { clicks: 0, impressions: 0, avgCtr: 0, avgPosition: 0 };

  let totalClicks = 0;
  let totalImpressions = 0;
  let totalPosition = 0;

  rows.forEach(rowArr => {
    const row = rowArr[0];
    totalClicks += row.clicks;
    totalImpressions += row.impressions;
    totalPosition += row.position;
  });

  return {
    clicks: totalClicks,
    impressions: totalImpressions,
    avgCtr: totalImpressions > 0 ? (totalClicks / totalImpressions * 100) : 0,
    avgPosition: totalPosition / rows.length
  };
}

// Get data arrays
const currentData = current.json['current data'] || [];
const previousData = previous.json['previous data'] || [];

// Calculate summaries
const currentTotals = calculateTotals(currentData);
const previousTotals = calculateTotals(previousData);

// Build comprehensive summary
let summary = `# ${reportType} Analysis\n\n`;

if (reportConfig) {
  summary += `**Report Period:** ${reportConfig.startDate} to ${reportConfig.endDate}\n`;
  summary += `**Comparison Period:** ${reportConfig.prevPeriodStartDate} to ${reportConfig.prevPeriodEndDate}\n\n`;
}

// Add performance overview
summary += `## Performance Overview\n\n`;
summary += `### ${currentLabel} Summary\n`;
summary += `- **Total Clicks:** ${currentTotals.clicks}\n`;
summary += `- **Total Impressions:** ${currentTotals.impressions}\n`;
summary += `- **Average CTR:** ${currentTotals.avgCtr.toFixed(2)}%\n`;
summary += `- **Average Position:** ${currentTotals.avgPosition.toFixed(1)}\n\n`;

summary += `### ${previousLabel} Summary\n`;
summary += `- **Total Clicks:** ${previousTotals.clicks}\n`;
summary += `- **Total Impressions:** ${previousTotals.impressions}\n`;
summary += `- **Average CTR:** ${previousTotals.avgCtr.toFixed(2)}%\n`;
summary += `- **Average Position:** ${previousTotals.avgPosition.toFixed(1)}\n\n`;

// Add change metrics
const clicksChange = ((currentTotals.clicks - previousTotals.clicks) / Math.max(previousTotals.clicks, 1) * 100);
const impressionsChange = ((currentTotals.impressions - previousTotals.impressions) / Math.max(previousTotals.impressions, 1) * 100);
const ctrChange = currentTotals.avgCtr - previousTotals.avgCtr;
const positionChange = currentTotals.avgPosition - previousTotals.avgPosition;

summary += `### Period-over-Period Changes\n`;
summary += `- **Clicks:** ${clicksChange > 0 ? '+' : ''}${clicksChange.toFixed(1)}%\n`;
summary += `- **Impressions:** ${impressionsChange > 0 ? '+' : ''}${impressionsChange.toFixed(1)}%\n`;
summary += `- **CTR:** ${ctrChange > 0 ? '+' : ''}${ctrChange.toFixed(2)}%\n`;
summary += `- **Average Position:** ${positionChange > 0 ? '+' : ''}${positionChange.toFixed(1)} (${positionChange > 0 ? 'worse' : 'better'})\n\n`;

// Add detailed tables
summary += `## Detailed Performance Data\n\n`;
summary += `### ${currentLabel} Details\n`;
summary += `${toMarkdownTable(currentData)}\n\n`;

summary += `### ${previousLabel} Details\n`;
summary += `${toMarkdownTable(previousData)}\n\n`;

// Add insights section
summary += `## Key Insights\n`;
summary += `This ${reportType.toLowerCase()} shows performance data for ${currentData.length} pages. `;
if (clicksChange > 10) {
  summary += `Clicks increased significantly by ${clicksChange.toFixed(1)}%. `;
} else if (clicksChange < -10) {
  summary += `Clicks decreased by ${Math.abs(clicksChange).toFixed(1)}%. `;
}

if (Math.abs(positionChange) > 2) {
  summary += `Average search position ${positionChange > 0 ? 'dropped' : 'improved'} by ${Math.abs(positionChange).toFixed(1)} positions. `;
}

summary += `Use this data to identify top-performing pages and opportunities for optimization.`;

return [
  {
    json: {
      reportType: reportType,
      reportPeriod: reportConfig ? {
        current: `${reportConfig.startDate} to ${reportConfig.endDate}`,
        previous: `${reportConfig.prevPeriodStartDate} to ${reportConfig.prevPeriodEndDate}`
      } : null,
      summary: summary,
      metrics: {
        current: currentTotals,
        previous: previousTotals,
        changes: {
          clicks: clicksChange,
          impressions: impressionsChange,
          ctr: ctrChange,
          position: positionChange
        }
      }
    }
  }
];

