/**
 * Error handling node
 */

const response = $input.item.json;
const statusCode = response.statusCode || 0;
const statusMessage = response.statusMessage || 'Unknown error';

return {
  json: {
    error: true,
    statusCode,
    message: statusMessage,
    details: `Failed to fetch data from Google Search Console API. Error ${statusCode}: ${statusMessage}`
    //requestParams: $node["Date Range Calculator1"].json
  }
};

/**
 * Error handling node
 */

const response = $input.item.json;
const statusCode = response.statusCode || 0;
const statusMessage = response.statusMessage || 'Unknown error';

return {
  json: {
    error: true,
    statusCode,
    message: statusMessage,
    details: `Failed to fetch data from Google Search Console API. Error ${statusCode}: ${statusMessage}`
    //requestParams: $node["Date Range Calculator1"].json
  }
};

// Get the input data - it's already an array with the structure we need
const inputArray = $input.all();
const inputData = inputArray[0].json || {};

const reportType = inputData.reportType || "Monthly";
const batchSize = parseInt(inputData.batchSize) || 5;

// Get URLs to process - they come directly from the input
let urls = inputData.urls || [];

// Validate that we have URLs to process
if (!Array.isArray(urls) || urls.length === 0) {
  throw new Error('No URLs provided. Please specify URLs in the input data.');
}

// Debug: Log the URLs to see what we're receiving
console.log('Received URLs:', JSON.stringify(urls, null, 2));

// Helper to format date as YYYY-MM-DD
function formatDate(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// Helper function to extract hostname from URL without using URL constructor
function extractHostname(url) {
  // Remove protocol
  let hostname = url.replace(/^https?:\/\//, '');

  // Remove path, query, and fragment
  hostname = hostname.split('/')[0];
  hostname = hostname.split('?')[0];
  hostname = hostname.split('#')[0];

  // Remove port if present
  hostname = hostname.split(':')[0];

  return hostname;
}

// Encode URL for GSC API
function encodeGscUrl(url) {
    try {
      // Clean the URL first
      if (typeof url !== 'string') {
        throw new Error(`URL must be a string, received: ${typeof url}`);
      }

      // Handle protocol-relative URLs (//example.com)
      if (url.startsWith('//')) {
        url = 'https:' + url;
      }
      // Handle URLs without protocol
      else if (!url.startsWith('http://') && !url.startsWith('https://')) {
        url = 'https://' + url;
      }

      // Extract hostname using custom function
      const hostname = extractHostname(url);

      if (!hostname || hostname.length === 0) {
        throw new Error(`Invalid hostname extracted from URL: ${url}`);
      }

      // Basic hostname validation
      if (!hostname.includes('.') || hostname.startsWith('.') || hostname.endsWith('.')) {
        throw new Error(`Invalid hostname format: ${hostname}`);
      }

      // Create the sc-domain format
      const scDomain = `sc-domain:${hostname}`;

      return {
        encodedSiteUrl: encodeURIComponent(scDomain),
        fullUrl: url
      };
    } catch (e) {
      throw new Error(`Invalid URL provided: "${url}". Error: ${e.message}. Please provide a valid URL.`);
    }
  }

// Dates
const today = new Date();
let startDate, endDate, prevPeriodStartDate, prevPeriodEndDate;

switch (reportType.toLowerCase()) {
  case "weekly":
    endDate = new Date(today);
    endDate.setDate(today.getDate() - today.getDay() - 1);
    startDate = new Date(endDate);
    startDate.setDate(endDate.getDate() - 6);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate);
    prevPeriodStartDate.setDate(prevPeriodEndDate.getDate() - 6);
    break;

  case "monthly":
    endDate = new Date(today.getFullYear(), today.getMonth(), 0);
    startDate = new Date(endDate.getFullYear(), endDate.getMonth(), 1);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate.getFullYear(), prevPeriodEndDate.getMonth(), 1);
    break;

  case "quarterly":
    const currentQuarter = Math.floor(today.getMonth() / 3);
    const prevQuarter = currentQuarter > 0 ? currentQuarter - 1 : 3;
    const prevQuarterYear = prevQuarter === 3 ? today.getFullYear() - 1 : today.getFullYear();
    endDate = new Date(prevQuarterYear, (prevQuarter + 1) * 3, 0);
    startDate = new Date(prevQuarterYear, prevQuarter * 3, 1);
    const prevPrevQuarter = prevQuarter > 0 ? prevQuarter - 1 : 3;
    const prevPrevQuarterYear = prevPrevQuarter === 3 ? prevQuarterYear - 1 : prevQuarterYear;
    prevPeriodEndDate = new Date(prevPrevQuarterYear, (prevPrevQuarter + 1) * 3, 0);
    prevPeriodStartDate = new Date(prevPrevQuarterYear, prevPrevQuarter * 3, 1);
    break;

  case "custom":
    if (inputData.customStartDate && inputData.customEndDate) {
      startDate = new Date(inputData.customStartDate);
      endDate = new Date(inputData.customEndDate);
      const dateDiff = endDate.getTime() - startDate.getTime();
      prevPeriodEndDate = new Date(startDate);
      prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
      prevPeriodStartDate = new Date(prevPeriodEndDate);
      prevPeriodStartDate.setTime(prevPeriodStartDate.getTime() - dateDiff);
    } else {
      throw new Error('Custom date range requires both customStartDate and customEndDate');
    }
    break;

  default:
    // Default to monthly if reportType is not recognized
    endDate = new Date(today.getFullYear(), today.getMonth(), 0);
    startDate = new Date(endDate.getFullYear(), endDate.getMonth(), 1);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate.getFullYear(), prevPeriodEndDate.getMonth(), 1);
}

// Common report config
const reportConfig = {
  reportType,
  startDate: formatDate(startDate),
  endDate: formatDate(endDate),
  prevPeriodStartDate: formatDate(prevPeriodStartDate),
  prevPeriodEndDate: formatDate(prevPeriodEndDate),
  batchSize,
  reportName: `${reportType.charAt(0).toUpperCase() + reportType.slice(1)} Report: ${formatDate(startDate)} to ${formatDate(endDate)}`
};

// Create a separate item per URL
return urls.map(url => {
  return {
    json: {
      reportConfig,
      urlToProcess: {
        url,
        encodedUrl: encodeGscUrl(url),
        processed: false,
        batchStart: 0,
        hasMoreData: true
      },
      result: {},
      previousPeriodResult: {}
    }
  };
});

const inputData = $('Code').item.json || {};
const reportType = inputData.reportType || "monthly";
const batchSize = parseInt(inputData.batchSize) || 5000;

// Get URLs to process
let urls = inputData.urls || [];
if (!Array.isArray(urls)) {
  if (typeof urls === 'string') {
    urls = urls.includes(',') ? urls.split(',').map(u => u.trim()) : [urls];
  } else {
    urls = [];
  }
}

// Validate that we have URLs to process
if (urls.length === 0) {
  throw new Error('No URLs provided. Please specify URLs in the input data from the Code node.');
}

// Helper to format date as YYYY-MM-DD
function formatDate(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// Helper function to extract hostname from URL without using URL constructor
function extractHostname(url) {
  // Remove protocol
  let hostname = url.replace(/^https?:\/\//, '');

  // Remove path, query, and fragment
  hostname = hostname.split('/')[0];
  hostname = hostname.split('?')[0];
  hostname = hostname.split('#')[0];

  // Remove port if present
  hostname = hostname.split(':')[0];

  return hostname;
}

// Encode URL for GSC API
function encodeGscUrl(url) {
    try {
      // Clean the URL first
      if (typeof url !== 'string') {
        throw new Error(`URL must be a string, received: ${typeof url}`);
      }

      // Handle protocol-relative URLs (//example.com)
      if (url.startsWith('//')) {
        url = 'https:' + url;
      }
      // Handle URLs without protocol
      else if (!url.startsWith('http://') && !url.startsWith('https://')) {
        url = 'https://' + url;
      }

      // Extract hostname using custom function
      const hostname = extractHostname(url);

      if (!hostname || hostname.length === 0) {
        throw new Error(`Invalid hostname extracted from URL: ${url}`);
      }

      // Basic hostname validation
      if (!hostname.includes('.') || hostname.startsWith('.') || hostname.endsWith('.')) {
        throw new Error(`Invalid hostname format: ${hostname}`);
      }

      // Create the sc-domain format
      const scDomain = `sc-domain:${hostname}`;

      return {
        encodedSiteUrl: encodeURIComponent(scDomain),
        fullUrl: url
      };
    } catch (e) {
      throw new Error(`Invalid URL provided: "${url}". Error: ${e.message}. Please provide a valid URL in the input data.`);
    }
  }

// Dates
const today = new Date();
let startDate, endDate, prevPeriodStartDate, prevPeriodEndDate;

switch (reportType.toLowerCase()) {
  case "weekly":
    endDate = new Date(today);
    endDate.setDate(today.getDate() - today.getDay() - 1);
    startDate = new Date(endDate);
    startDate.setDate(endDate.getDate() - 6);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate);
    prevPeriodStartDate.setDate(prevPeriodEndDate.getDate() - 6);
    break;

  case "monthly":
    endDate = new Date(today.getFullYear(), today.getMonth(), 0);
    startDate = new Date(endDate.getFullYear(), endDate.getMonth(), 1);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate.getFullYear(), prevPeriodEndDate.getMonth(), 1);
    break;

  case "quarterly":
    const currentQuarter = Math.floor(today.getMonth() / 3);
    const prevQuarter = currentQuarter > 0 ? currentQuarter - 1 : 3;
    const prevQuarterYear = prevQuarter === 3 ? today.getFullYear() - 1 : today.getFullYear();
    endDate = new Date(prevQuarterYear, (prevQuarter + 1) * 3, 0);
    startDate = new Date(prevQuarterYear, prevQuarter * 3, 1);
    const prevPrevQuarter = prevQuarter > 0 ? prevQuarter - 1 : 3;
    const prevPrevQuarterYear = prevPrevQuarter === 3 ? prevQuarterYear - 1 : prevQuarterYear;
    prevPeriodEndDate = new Date(prevPrevQuarterYear, (prevPrevQuarter + 1) * 3, 0);
    prevPeriodStartDate = new Date(prevPrevQuarterYear, prevPrevQuarter * 3, 1);
    break;

  case "custom":
    if (inputData.customStartDate && inputData.customEndDate) {
      startDate = new Date(inputData.customStartDate);
      endDate = new Date(inputData.customEndDate);
      const dateDiff = endDate.getTime() - startDate.getTime();
      prevPeriodEndDate = new Date(startDate);
      prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
      prevPeriodStartDate = new Date(prevPeriodEndDate);
      prevPeriodStartDate.setTime(prevPeriodStartDate.getTime() - dateDiff);
    } else {
      throw new Error('Custom date range requires both customStartDate and customEndDate');
    }
    break;

  default:
    endDate = new Date(today.getFullYear(), today.getMonth(), 0);
    startDate = new Date(endDate.getFullYear(), endDate.getMonth(), 1);
    prevPeriodEndDate = new Date(startDate);
    prevPeriodEndDate.setDate(prevPeriodEndDate.getDate() - 1);
    prevPeriodStartDate = new Date(prevPeriodEndDate.getFullYear(), prevPeriodEndDate.getMonth(), 1);
}

// Common report config
const reportConfig = {
  reportType,
  startDate: formatDate(startDate),
  endDate: formatDate(endDate),
  prevPeriodStartDate: formatDate(prevPeriodStartDate),
  prevPeriodEndDate: formatDate(prevPeriodEndDate),
  batchSize,
  reportName: `${reportType.charAt(0).toUpperCase() + reportType.slice(1)} Report: ${formatDate(startDate)} to ${formatDate(endDate)}`
};

// Create a separate item per URL
return urls.map(url => {
  return {
    json: {
      reportConfig,
      urlToProcess: {
        url,
        encodedUrl: encodeGscUrl(url),
        processed: false,
        batchStart: 0,
