// n8n Code Node - Handle Inconsistent LLM Output
// This handles both complex and simple formats from your LLM

const inputData = $input.all();

function detectAndTransform(llmOutput) {
  try {
    console.log("Raw LLM Output:", JSON.stringify(llmOutput, null, 2));

    // Case 1: Already in correct simple format
    if (llmOutput.topics && Array.isArray(llmOutput.topics)) {
      console.log("✅ Detected: Simple format - passing through");
      // Validate structure
      const validTopics = llmOutput.topics.filter(item => 
        item.topic && typeof item.description === 'string'
      );
      return { topics: validTopics };
    }

    // Case 2: Complex nested format
    let topicsArray = [];

    // Handle array wrapper
    if (Array.isArray(llmOutput)) {
      const firstItem = llmOutput[0];
      if (firstItem?.response?.output) {
        topicsArray = firstItem.response.output;
        console.log("✅ Detected: Complex format (array wrapper)");
      } else if (firstItem?.topics) {
        topicsArray = firstItem.topics;
        console.log("✅ Detected: Simple format in array");
      }
    }
    // Handle direct object
    else if (llmOutput?.response?.output) {
      topicsArray = llmOutput.response.output;
      console.log("✅ Detected: Complex format (direct object)");
    }
    // Handle direct output array
    else if (llmOutput?.output && Array.isArray(llmOutput.output)) {
      topicsArray = llmOutput.output;
      console.log("✅ Detected: Direct output array");
    }

    // Transform complex format to simple
    if (topicsArray.length > 0) {
      const transformedTopics = topicsArray.map(item => ({
        topic: item.topic || '',
        description: extractDescription(item.description)
      })).filter(item => item.topic); // Remove empty topics

      console.log(`✅ Transformed ${transformedTopics.length} topics`);
      return { topics: transformedTopics };
    }

    // Fallback: try to extract from any structure
    console.log("⚠️ Fallback: Attempting to extract from unknown structure");
    return attemptFallbackExtraction(llmOutput);

  } catch (error) {
    console.error("❌ Transform error:", error);
    return { topics: [] };
  }
}

function extractDescription(desc) {
  if (typeof desc === 'string') {
    return desc;
  }
  if (typeof desc === 'object' && desc !== null) {
    // Priority order for nested description object
    return desc.mofu_angle || 
           desc.description || 
           desc.summary || 
           JSON.stringify(desc);
  }
  return '';
}

function attemptFallbackExtraction(data) {
  // Recursively search for topic-like structures
  function findTopics(obj, path = '') {
    if (!obj || typeof obj !== 'object') return [];

    let found = [];

    for (const [key, value] of Object.entries(obj)) {
      if (key === 'topics' && Array.isArray(value)) {
        console.log(`🔍 Found topics at: ${path}.${key}`);
        found = found.concat(value);
      } else if (Array.isArray(value)) {
        // Check if array contains topic objects
        const topicLike = value.filter(item => 
          item && typeof item === 'object' && item.topic
        );
        if (topicLike.length > 0) {
          console.log(`🔍 Found topic-like array at: ${path}.${key}`);
          found = found.concat(topicLike);
        }
        // Recurse into array items
        value.forEach((item, idx) => {
          found = found.concat(findTopics(item, `${path}.${key}[${idx}]`));
        });
      } else if (typeof value === 'object') {
        found = found.concat(findTopics(value, `${path}.${key}`));
      }
    }

    return found;
  }

  const foundTopics = findTopics(data);
  const transformedTopics = foundTopics.map(item => ({
    topic: item.topic || '',
    description: extractDescription(item.description)
  })).filter(item => item.topic);

  console.log(`🔍 Fallback found ${transformedTopics.length} topics`);
  return { topics: transformedTopics };
}

// Process all input items
const outputData = inputData.map((item, index) => {
  console.log(`\n--- Processing item ${index + 1} ---`);

  // Get LLM response - adjust field names as needed
  const llmResponse = item.json.response || 
                      item.json.choices?.[0]?.message?.content || 
                      item.json.content || 
                      item.json;

  // Handle JSON string responses
  let parsedResponse = llmResponse;
  if (typeof llmResponse === 'string') {
    try {
      parsedResponse = JSON.parse(llmResponse);
