// --- WORDPRESS URL REPLACER AND ARTICLE FORMATTER ---
// This code replaces Airtable URLs in blog HTML with WordPress CDN URLs
// Input: WordPress API response with media URLs
// Output: WordPress article object ready for API

// --- 1. GET ALL DATA FROM EDIT FIELDS26 NODE ---

let blogHtml;
let thumbnailUrl = "";
let thumbnailAltText = "";
let tags = "";
let title = "";
let slug = "";
let metaTitle = "";
let metaDescription = "";
let metaTitleType = "";

// Get all data from Edit Fields26 node
try {
  const editFields26 = $('Edit Fields26').first();
