  } else {
    console.log("Edit Fields26 data:", editFields26 ? editFields26.json : "Node not found");
  }
} catch (error) {
  console.log("Could not access Edit Fields26 node:", error.message);
}

if (!blogHtml) {
  console.error("Blog HTML not found in Edit Fields26!");
  return {
    error: "Blog HTML not found in Edit Fields26"
  };
}

console.log("Blog HTML found, length:", blogHtml.length);

// --- 2. EXTRACT WORDPRESS URLS FROM ALL INPUT ITEMS ---

const allInputs = $input.all();
console.log("Total input items:", allInputs.length);

let newImageUrls = [];

try {
  // Process ALL input items, not just the first one
  allInputs.forEach((currentInput, inputIndex) => {
    console.log(`Processing input item ${inputIndex}:`, Object.keys(currentInput || {}));

    let mediaObjects = [];

    // Handle different input structures for each item
    if (currentInput && Array.isArray(currentInput.json)) {
      mediaObjects = currentInput.json;
      console.log(`✅ Item ${inputIndex}: Found json array (n8n structure), length:`, mediaObjects.length);
    } else if (Array.isArray(currentInput)) {
      mediaObjects = currentInput;
      console.log(`✅ Item ${inputIndex}: Input is direct array, length:`, mediaObjects.length);
    } else if (currentInput && currentInput.data && Array.isArray(currentInput.data)) {
      mediaObjects = currentInput.data;
      console.log(`✅ Item ${inputIndex}: Found data array, length:`, mediaObjects.length);
    } else if (currentInput && currentInput.json && currentInput.json.source_url) {
      // Single media object in json property
      mediaObjects = [currentInput.json];
      console.log(`✅ Item ${inputIndex}: Found single media object in json`);
    } else if (currentInput && currentInput.source_url) {
      // Direct single media object
      mediaObjects = [currentInput];
      console.log(`✅ Item ${inputIndex}: Found direct single media object`);
    } else {
      console.log(`❌ Item ${inputIndex}: Structure not recognized, trying to find media data...`);
      console.log(`Available keys:`, Object.keys(currentInput || {}));

      // Try to find any array or media object in the input
      for (const key in currentInput) {
        if (Array.isArray(currentInput[key]) && currentInput[key].length > 0) {
          const firstItem = currentInput[key][0];
          if (firstItem && (firstItem.source_url || firstItem.id)) {
            mediaObjects = currentInput[key];
            console.log(`✅ Item ${inputIndex}: Found media objects in ${key}, length:`, mediaObjects.length);
            break;
          }
        } else if (currentInput[key] && currentInput[key].source_url) {
          mediaObjects = [currentInput[key]];
          console.log(`✅ Item ${inputIndex}: Found single media object in ${key}`);
          break;
        }
      }
    }

    // Extract URLs from this input's media objects
    mediaObjects.forEach((mediaObj, mediaIndex) => {
      console.log(`Item ${inputIndex}, Media ${mediaIndex}:`, {
        id: mediaObj.id || 'no-id',
        title: mediaObj.title?.rendered || 'no-title',
        hasSourceUrl: !!mediaObj.source_url,
        hasMediaDetails: !!mediaObj.media_details
      });

      if (mediaObj.source_url) {
        // Use full size image URL
        newImageUrls.push(mediaObj.source_url);
        console.log(`✅ Item ${inputIndex}, Media ${mediaIndex}: Added URL:`, mediaObj.source_url);
      } else if (mediaObj.media_details && mediaObj.media_details.sizes && mediaObj.media_details.sizes.full) {
        // Fallback to full size from media_details
        const fullSizeUrl = mediaObj.media_details.sizes.full.source_url;
        newImageUrls.push(fullSizeUrl);
        console.log(`✅ Item ${inputIndex}, Media ${mediaIndex}: Added URL from media_details:`, fullSizeUrl);
      } else {
        console.log(`❌ Item ${inputIndex}, Media ${mediaIndex}: Missing source_url:`, Object.keys(mediaObj || {}));
      }
    });
  });

} catch (error) {
  console.log("❌ Error extracting WordPress URLs:", error.message);
  console.log("Full error:", error);
}

console.log("Final extracted WordPress URLs from all items:", newImageUrls);
console.log("Total WordPress URLs found:", newImageUrls.length);

// --- 3. EXTRACT URLS FROM HTML (AIRTABLE FIRST, THEN TEMP URLS) ---

// First, try to find Airtable URLs
const airtableRegex = /https:\/\/v5\.airtableusercontent\.com[^"\s]+/g;
let urlsToReplace = blogHtml.match(airtableRegex) || [];
let urlType = "airtable";

console.log("Extracted Airtable URLs from HTML:", urlsToReplace);

// If no Airtable URLs found, look for temp URLs
if (urlsToReplace.length === 0) {
  console.log("No Airtable URLs found, searching for temp URLs...");

  // Define regex patterns for common temp file services (support both http and https)
  const tempUrlPatterns = [
    /https?:\/\/tmpfiles\.org\/dl\/\d+\/[^"\s]+/g,
    /https?:\/\/temp\.sh\/[^"\s]+/g,
    /https?:\/\/transfer\.sh\/[^"\s]+/g,
    /https?:\/\/0x0\.st\/[^"\s]+/g,
    /https?:\/\/file\.io\/[^"\s]+/g,
    /https?:\/\/gofile\.io\/d\/[^"\s]+/g,
    /https?:\/\/[^"\s]*temp[^"\s]*\.[^"\s]+\.(?:jpg|jpeg|png|gif|webp|svg)/gi
  ];

  // Try each pattern until we find URLs
  for (let i = 0; i < tempUrlPatterns.length && urlsToReplace.length === 0; i++) {
    const pattern = tempUrlPatterns[i];
    urlsToReplace = blogHtml.match(pattern) || [];
    if (urlsToReplace.length > 0) {
      urlType = "temp";
      console.log(`Found ${urlsToReplace.length} temp URLs using pattern ${i + 1}:`, urlsToReplace);
      break;
    }
  }

  // If still no temp URLs found, try a broader search
  if (urlsToReplace.length === 0) {
    console.log("No specific temp URLs found, searching for any external image URLs...");

    // Look for any external image URLs that are not WordPress or common CDNs
    const allImageUrlRegex = /https?:\/\/[^"\s]+\.(?:jpg|jpeg|png|gif|webp|svg)/gi;
    const allImageUrls = blogHtml.match(allImageUrlRegex) || [];

    // Filter out known permanent services
    const permanentDomains = [
      'wordpress.com',
      'wp.com', 
      'gravatar.com',
      'imgur.com',
      'cloudinary.com',
      'amazonaws.com',
      'googleusercontent.com',
      'dropbox.com',
      'github.com',
      'githubusercontent.com'
    ];

    urlsToReplace = allImageUrls.filter(url => {
      return !permanentDomains.some(domain => url.includes(domain));
    });

    if (urlsToReplace.length > 0) {
      urlType = "external";
      console.log(`Found ${urlsToReplace.length} external image URLs (potentially temporary):`, urlsToReplace);
    }
  }
}

console.log(`Final URLs to replace (${urlType}):`, urlsToReplace);

// Extract unique URLs only (remove duplicates)
const uniqueUrlsToReplace = [...new Set(urlsToReplace)];
console.log(`Unique ${urlType} URLs to replace:`, uniqueUrlsToReplace.length);

// --- 4. VALIDATE DATA BEFORE REPLACEMENT ---
const finalUrlsToReplace = uniqueUrlsToReplace.length > 0 ? uniqueUrlsToReplace : urlsToReplace;

// If no URLs need replacement, we'll still publish the blog as-is
let skipUrlReplacement = false;
if (finalUrlsToReplace.length === 0) {
  console.log("✅ No URLs found that need replacement - blog will be published as-is");
  skipUrlReplacement = true;
}

// Only check for WordPress URLs if we actually have URLs to replace
if (!skipUrlReplacement && newImageUrls.length === 0) {
  console.warn("No WordPress URLs found!");

  // Try alternative extraction methods
  console.log("Attempting alternative URL extraction from all inputs...");
  try {
    allInputs.forEach((input, index) => {
      const inputStr = JSON.stringify(input);
      const urlMatches = inputStr.match(/https?:\/\/[^"]+\.(?:jpg|jpeg|png|gif|webp)/gi);
      if (urlMatches && urlMatches.length > 0) {
        console.log(`Found URLs in input ${index} via string matching:`, urlMatches);
        newImageUrls.push(...urlMatches);
      }
    });
    // Remove duplicates
    newImageUrls = [...new Set(newImageUrls)];
  } catch (e) {
    console.log("Alternative extraction failed:", e.message);
  }

  if (newImageUrls.length === 0) {
    return {
      error: "URLs found to replace but no WordPress URLs available for replacement",
      debugInfo: {
        urlsToReplace: finalUrlsToReplace.length,
        totalInputs: allInputs.length,
        inputStructures: allInputs.map((input, i) => ({
          index: i,
          keys: Object.keys(input || {}),
          isArray: Array.isArray(input)
        }))
      }
    };
  }
}

console.log("Final validation:");
if (skipUrlReplacement) {
  console.log("- No URL replacement needed - proceeding with original content");
} else {
  console.log(`- ${urlType} URLs to replace:`, finalUrlsToReplace.length);
  console.log("- WordPress URLs available:", newImageUrls.length);
}

// --- 5. CREATE PROPER URL MAPPING AND REPLACE ---
let updatedBlogHtml = blogHtml;
let replacementCount = 0;

// Only perform URL replacement if we have URLs to replace
if (!skipUrlReplacement) {
  // Helper function to escape special regex characters
  function escapeRegExp(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  // Create a mapping strategy
  console.log("Creating URL mapping...");
  console.log(`${urlType} URLs to replace:`, finalUrlsToReplace.length);
  console.log("WordPress URLs available:", newImageUrls.length);

  // Strategy 1: Direct 1:1 mapping if counts match
  let urlMapping = {};

  if (finalUrlsToReplace.length <= newImageUrls.length) {
    // We have enough WordPress URLs
    finalUrlsToReplace.forEach((originalUrl, index) => {
      if (index < newImageUrls.length) {
        urlMapping[originalUrl] = newImageUrls[index];
        console.log(`Mapping ${index + 1}: ${originalUrl} -> ${newImageUrls[index]}`);
      }
    });
  } else {
    // More original URLs than WordPress URLs - cycle through WordPress URLs
    console.warn(`More ${urlType} URLs than WordPress URLs - cycling through available URLs`);
    finalUrlsToReplace.forEach((originalUrl, index) => {
      const wpUrlIndex = index % newImageUrls.length;
      urlMapping[originalUrl] = newImageUrls[wpUrlIndex];
      console.log(`Mapping ${index + 1}: ${originalUrl} -> ${newImageUrls[wpUrlIndex]} (cycling)`);
    });
  }

  // Perform all replacements using the mapping
  Object.keys(urlMapping).forEach((originalUrl, index) => {
    const newUrl = urlMapping[originalUrl];

    console.log(`Replacing: ${originalUrl} -> ${newUrl}`);
    const regex = new RegExp(escapeRegExp(originalUrl), 'g');
    const beforeReplace = updatedBlogHtml;
    updatedBlogHtml = updatedBlogHtml.replace(regex, newUrl);

    // Check if replacement actually happened
    if (beforeReplace !== updatedBlogHtml) {
      replacementCount++;
      console.log(`✅ Replacement ${index + 1} successful`);
    } else {
      console.log(`❌ Replacement ${index + 1} failed - URL not found in HTML`);
      // Try to find similar URL patterns for debugging
      const similarUrls = blogHtml.match(new RegExp(escapeRegExp(originalUrl.substring(0, 50)), 'g'));
      if (similarUrls) {
        console.log("Found similar URL patterns:", similarUrls);
      }
    }
  });
} else {
  console.log("✅ Skipping URL replacement - no URLs found that need replacement");
}

// --- 6. REMOVE DUPLICATE TITLE FROM CONTENT ---
// Remove any <h1> tags from the content to prevent duplicate titles
// since WordPress will display the post title separately
console.log("Checking for duplicate title in content...");
const h1Regex = /<h1[^>]*>.*?<\/h1>/gi;
const h1Matches = updatedBlogHtml.match(h1Regex);
if (h1Matches && h1Matches.length > 0) {
  console.log(`Found ${h1Matches.length} <h1> tag(s) in content, removing to prevent duplicate title...`);
  updatedBlogHtml = updatedBlogHtml.replace(h1Regex, '');
  console.log("✅ Removed <h1> tags from content");
} else {
  console.log("No <h1> tags found in content");
}

// --- 7. EXTRACT TITLE AND GENERATE SLUG ---
if (!title) {
  // Fallback: extract title from HTML if not provided in Edit Fields26
  const titleMatch = blogHtml.match(/<h1[^>]*>(.*?)<\/h1>/i);
  title = titleMatch ? titleMatch[1].replace(/<[^>]*>/g, '') : "Blog Post";
  console.log("Using title from HTML:", title);
} else {
  console.log("Using title from Edit Fields26:", title);
}

// Generate slug if not provided in Edit Fields26
if (!slug) {
  // Generate slug from title
  slug = title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '') // Remove special characters
    .replace(/\s+/g, '-')         // Replace spaces with hyphens
    .replace(/-+/g, '-')          // Replace multiple hyphens with single
    .replace(/^-|-$/g, '');       // Remove leading/trailing hyphens

  console.log("Generated slug from title:", slug);
} else {
  // Clean the provided slug to ensure it's URL-friendly
  slug = slug
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');

  console.log("Using cleaned slug from Edit Fields26:", slug);
}

// Use title as meta title fallback if not provided
if (!metaTitle) {
  metaTitle = title;
  console.log("Using post title as meta title:", metaTitle);
}

// --- 8. FORMAT AS WORDPRESS ARTICLE OBJECT WITH UPLOADED THUMBNAIL ---

const wordpressArticle = {
  title: title,
  content: updatedBlogHtml,
  status: "draft",
  slug: slug,
  excerpt: metaDescription
};

/*
// Add SEO meta fields based on Meta Title Type
if (metaTitle || metaDescription) {
  if (metaTitleType === "Yoast") {
    // Add Yoast SEO meta fields
    wordpressArticle.yoast_head_json = {
      title: metaTitle,
      description: metaDescription
    };
    console.log("✅ Added Yoast SEO meta fields:", { metaTitle, metaDescription });
  } else if (metaTitleType === "Rank-Math") {
    // Add RankMath meta fields
    wordpressArticle.meta = {
      rank_math_title: metaTitle,
      rank_math_description: metaDescription
    };
    console.log("✅ Added RankMath meta fields:", { metaTitle, metaDescription });
  } else {
    // Default to RankMath if Meta Title Type is not specified or unrecognized
    wordpressArticle.meta = {
      rank_math_title: metaTitle,
      rank_math_description: metaDescription
    };
    console.log("⚠️ Meta Title Type not specified or unrecognized, defaulting to RankMath");
    console.log("✅ Added RankMath meta fields (default):", { metaTitle, metaDescription });
  }
}
*/
// Get thumbnail media ID from HTTP Request18 node
try {
  const thumbnailUploadNode = $('HTTP Request18').first();

  if (thumbnailUploadNode && thumbnailUploadNode.json) {
    let thumbnailMediaId = null;
    let thumbnailSourceUrl = null;

    // Handle array response (your case)
    if (Array.isArray(thumbnailUploadNode.json) && thumbnailUploadNode.json.length > 0) {
      thumbnailMediaId = thumbnailUploadNode.json[0].id;
      thumbnailSourceUrl = thumbnailUploadNode.json[0].source_url;
      console.log("✅ Found thumbnail in array response, media ID:", thumbnailMediaId);
    } 
    // Handle direct object response
    else if (thumbnailUploadNode.json.id) {
      thumbnailMediaId = thumbnailUploadNode.json.id;
      thumbnailSourceUrl = thumbnailUploadNode.json.source_url;
      console.log("✅ Found thumbnail in direct response, media ID:", thumbnailMediaId);
    }

    if (thumbnailMediaId) {
      wordpressArticle.featured_media = thumbnailMediaId;
      console.log("✅ Using uploaded thumbnail as featured image, media ID:", thumbnailMediaId);
      console.log("Thumbnail URL:", thumbnailSourceUrl);
    } else {
      console.log("❌ No valid thumbnail media ID found in HTTP Request18 response");
    }

  } else {
    console.log("❌ HTTP Request18 node not found or empty response");
  }

  // Fallback: Use first WordPress media object as thumbnail if no uploaded thumbnail
  if (!wordpressArticle.featured_media) {
    console.log("Checking for existing WordPress media as fallback...");

    let featuredMediaId = null;

    allInputs.forEach(input => {
      if (!featuredMediaId) {
        if (input && input.json && Array.isArray(input.json) && input.json[0] && input.json[0].id) {
          featuredMediaId = input.json[0].id;
        } else if (input && input.json && input.json.id) {
          featuredMediaId = input.json.id;
        } else if (input && input.id) {
          featuredMediaId = input.id;
        }
      }
    });

    if (featuredMediaId) {
      wordpressArticle.featured_media = featuredMediaId;
      console.log("✅ Using existing WordPress media as featured image:", featuredMediaId);
    } else {
      console.log("❌ No featured image available");
    }
  }

} catch (error) {
  console.log("❌ Error accessing HTTP Request18 node:", error.message);
  console.log("Proceeding without featured image...");
}

if (skipUrlReplacement) {
  console.log("✅ WordPress article object created successfully (no URL replacements needed)!");
} else {
  console.log(`Successfully replaced ${replacementCount} out of ${finalUrlsToReplace.length} ${urlType} URLs`);
  console.log("✅ WordPress article object created successfully!");
}

console.log("Article summary:", {
  title: wordpressArticle.title,
  slug: wordpressArticle.slug,
  metaTitle: metaTitle || "none",
  metaDescription: metaDescription || "none",
  contentLength: wordpressArticle.content.length,
  status: wordpressArticle.status,
  hasFeaturedImage: !!wordpressArticle.featured_media,
  featuredMediaId: wordpressArticle.featured_media || "none",
  totalImageReplacements: replacementCount,
  wordpressUrlsUsed: skipUrlReplacement ? 0 : newImageUrls.length,
  urlTypeReplaced: skipUrlReplacement ? "none" : urlType,
  replacementSkipped: skipUrlReplacement,
  hasSEOFields: !!(metaTitle || metaDescription)
});

// --- 9. RETURN WORDPRESS ARTICLE OBJECT ---
return wordpressArticle;

// --- SHOPIFY GRAPHQL FILE CREATOR FOR AIRTABLE DATA ---
// This code node creates a GraphQL mutation for Shopify file uploads
// Input: Airtable data structure with Images array and optional alt text
// Output: GraphQL mutation with files array

// --- 1. GET IMAGE URLS FROM AIRTABLE INPUT ---

let imageUrls = [];
let altTexts = [];
let blogContent = "";

try {
  const inputData = $input.all();
  console.log("Input data received:", inputData.length, "items");

  if (inputData && inputData.length > 0) {
    const firstItem = inputData[0];

    // Handle different input structures
    let dataObj = firstItem;
    if (firstItem.json) {
      dataObj = firstItem.json; // n8n wrapped structure
    }

    // Extract blog content for context
    if (dataObj.Blog) {
      blogContent = dataObj.Blog;
      console.log("Blog content found, length:", blogContent.length);
    }

    // Extract image URLs from Images array (keep all URLs including duplicates)
    if (dataObj.Images && Array.isArray(dataObj.Images)) {
      imageUrls = dataObj.Images.filter(url => url && url.includes('http'));
      console.log("Found", imageUrls.length, "image URLs");
    }

    // Extract alt texts if provided
    if (dataObj.ImageAlts && Array.isArray(dataObj.ImageAlts)) {
      altTexts = dataObj.ImageAlts;
      console.log("Found", altTexts.length, "alt texts");
    } else if (dataObj.AltTexts && Array.isArray(dataObj.AltTexts)) {
      altTexts = dataObj.AltTexts;
      console.log("Found", altTexts.length, "alt texts");
    }

    console.log("Data object structure:", Object.keys(dataObj));
  }

} catch (error) {
  console.log("Error processing input:", error.message);
}

console.log("Extracted image URLs:", imageUrls);
console.log("Extracted alt texts:", altTexts);

// --- 2. VALIDATE INPUT ---
if (!imageUrls || imageUrls.length === 0) {
  return {
    error: "No image URLs found in Images array"
  };
}

// --- 3. BUILD FILES ARRAY ---
const filesArray = imageUrls.map((url, index) => {
  // Ensure HTTPS (Shopify requirement)
  const httpsUrl = url.replace(/^http:\/\//, 'https://');

  // Use provided alt text or fallback to generic description
  const altText = altTexts[index] || `Image ${index + 1}`;

  return {
    alt: altText,
    contentType: "IMAGE",
    originalSource: httpsUrl
  };
});

// --- 4. CREATE GRAPHQL MUTATION ---
const graphqlMutation = {
  query: "mutation fileCreate($files: [FileCreateInput!]!) { fileCreate(files: $files) { files { id fileStatus alt createdAt ... on MediaImage { image { url } } } userErrors { field message } } }",
  variables: {
    files: filesArray
  }
};

// --- 5. RETURN RESULT ---
return graphqlMutation;

// --- GET SHOPIFY FILE URLS ---
// This code extracts file IDs from the fileCreate response and creates a query to get the image URLs

// --- 1. EXTRACT FILE IDS FROM RESPONSE ---
let fileIds = [];

try {
  const response = $json;

  if (response.data && response.data.fileCreate && response.data.fileCreate.files) {
    fileIds = response.data.fileCreate.files.map(file => file.id);
    console.log("Extracted file IDs:", fileIds);
  }
} catch (error) {
  console.log("Error extracting file IDs:", error.message);
}

// --- 2. VALIDATE INPUT ---
if (!fileIds || fileIds.length === 0) {
  return {
    error: "No file IDs found in response"
  };
}

// --- 3. CREATE GRAPHQL QUERY TO GET FILE URLS ---
// Use the 'node' field to query files by ID (standard GraphQL pattern)
const fileQueries = fileIds.map((id, index) => {
  return `file${index}: node(id: "${id}") {
    id
    ... on MediaImage {
      alt
      mediaContentType
      image {
        url
        altText
      }
    }
  }`;
}).join('\n  ');

const getFilesQuery = {
  query: `query GetFiles {
  ${fileQueries}
}`
};

// --- 4. RETURN QUERY ---
return getFilesQuery;

// --- SHOPIFY URL REPLACER AND ARTICLE FORMATTER ---
// This code replaces Airtable URLs in blog HTML with Shopify CDN URLs
// Input: Shopify GraphQL response with file URLs
// Output: Shopify article object ready for API

// --- 1. GET ALL DATA FROM EDIT FIELDS42 NODE ---

let blogHtml;
let thumbnailUrl = "";
let thumbnailAltText = "";
let tags = "";
let title = "";
let handle = "";

// Get all data from Edit Fields42 node
try {
  const editFields42 = $('Edit Fields42').first();
  if (editFields42 && editFields42.json) {
    // Get blog HTML
    if (editFields42.json.Blog) {
      blogHtml = editFields42.json.Blog;
      console.log("Found blog HTML from Edit Fields42 node");
    }

    // Get thumbnail data
    if (editFields42.json.Thumbnail) {
      thumbnailUrl = editFields42.json.Thumbnail;
      console.log("Found thumbnail URL from Edit Fields42:", thumbnailUrl);
    }

    // Get thumbnail name (alt text)
    if (editFields42.json.ThumbnailName) {
      thumbnailAltText = editFields42.json.ThumbnailName;
      console.log("Found thumbnail alt text from Edit Fields42:", thumbnailAltText);
    }

    // Get tags
    if (editFields42.json.Tag) {
      tags = editFields42.json.Tag;
      console.log("Found tags from Edit Fields42:", tags);
    }

    // Get title if available
    if (editFields42.json.Title) {
      title = editFields42.json.Title;
      console.log("Found title from Edit Fields42:", title);
    }

    // Get handle (slug) if available
    if (editFields42.json.Slug) {
      handle = editFields42.json.Slug;
      console.log("Found handle from Edit Fields42:", handle);
    }

    console.log("Edit Fields42 data processed successfully");
  } else {
    console.log("Edit Fields42 data:", editFields42 ? editFields42.json : "Node not found");
  }
} catch (error) {
  console.log("Could not access Edit Fields42 node:", error.message);
}

if (!blogHtml) {
  console.error("Blog HTML not found in Edit Fields42!");
  return {
    error: "Blog HTML not found in Edit Fields42"
  };
}

console.log("Blog HTML found, length:", blogHtml.length);

// --- 2. CHECK IF IMAGES EXIST IN EDIT FIELDS44 ---

let shouldReplaceUrls = true;
let imagesData = null;

try {
  const editFields44 = $('Edit Fields44').first();
  if (editFields44 && editFields44.json && editFields44.json.Images) {
    imagesData = editFields44.json.Images;
    console.log("Found images data in Edit Fields44:", imagesData);

    // Check if images data is meaningful (not null, not empty array, not empty string)
    if (!imagesData || 
        (Array.isArray(imagesData) && imagesData.length === 0) ||
        (typeof imagesData === 'string' && imagesData.trim() === '')) {
      shouldReplaceUrls = false;
      console.log("Images data is empty or null - skipping URL replacement");
    } else {
      console.log("Images data found - will proceed with URL replacement");
    }
  } else {
    shouldReplaceUrls = false;
    console.log("No images found in Edit Fields44 - skipping URL replacement");
  }
} catch (error) {
  console.log("Could not access Edit Fields44 node:", error.message);
  shouldReplaceUrls = false;
}

// --- 3. INITIALIZE VARIABLES AT PROPER SCOPE ---

let updatedBlogHtml = blogHtml;
let replacementCount = 0;
let urlsToReplace = []; // Declare at top level to avoid scope issues
let newImageUrls = [];

if (!shouldReplaceUrls) {
  console.log("🔄 Skipping URL replacement - no images to process");
  console.log("Using original blog HTML without modifications");
} else {
  console.log("🔄 Processing image URL replacements...");

  // --- EXTRACT SHOPIFY URLS FROM GRAPHQL RESPONSE ---
  const currentInput = $input.all()[0];
  console.log("Current input structure:", Object.keys(currentInput || {}));

  try {
    if (currentInput && currentInput.data) {
      console.log("Found data object with keys:", Object.keys(currentInput.data));

      // Extract URLs from GraphQL response
      const files = currentInput.data;

      // Get all file objects (file0, file1, file2, etc.)
      Object.keys(files).forEach(fileKey => {
        console.log(`Processing ${fileKey}:`, files[fileKey]);

        if (fileKey.startsWith('file')) {
          const fileObj = files[fileKey];
          console.log(`${fileKey} structure:`, Object.keys(fileObj || {}));

          if (fileObj && fileObj.image && fileObj.image.url) {
            newImageUrls.push(fileObj.image.url);
            console.log(`✅ Found Shopify URL from ${fileKey}:`, fileObj.image.url);
          } else {
            console.log(`❌ ${fileKey} missing image.url:`, {
              hasImage: !!fileObj.image,
              imageStructure: fileObj.image ? Object.keys(fileObj.image) : 'no image'
            });
          }
        }
      });
    } else {
      console.log("No data object found in input:", currentInput);
    }
  } catch (error) {
    console.log("Error extracting Shopify URLs:", error.message);
    console.log("Full error:", error);
  }

  console.log("Final extracted Shopify URLs:", newImageUrls);

  // --- EXTRACT AIRTABLE URLS FROM HTML AND ANALYZE ---
  const airtableRegex = /https:\/\/v5\.airtableusercontent\.com[^"\s]+/g;
  urlsToReplace = blogHtml.match(airtableRegex) || [];
  console.log("Extracted Airtable URLs from HTML:", urlsToReplace);

  // Extract unique URLs only (remove duplicates)
  const uniqueUrlsToReplace = [...new Set(urlsToReplace)];
  console.log("Unique Airtable URLs to replace:", uniqueUrlsToReplace.length);

  // Also extract any other image URLs that might need replacement
  const allImageUrlRegex = /https:\/\/[^"\s]+\.(?:jpg|jpeg|png|gif|webp|svg)/gi;
  const allImageUrls = blogHtml.match(allImageUrlRegex) || [];
  console.log("All image URLs found in HTML:", allImageUrls.length);

  // Filter for only Airtable URLs
  const airtableImageUrls = allImageUrls.filter(url => url.includes('airtableusercontent.com'));
  console.log("Airtable image URLs:", airtableImageUrls.length);

  // --- VALIDATE DATA BEFORE REPLACEMENT ---
  const finalUrlsToReplace = uniqueUrlsToReplace.length > 0 ? uniqueUrlsToReplace : urlsToReplace;

  if (finalUrlsToReplace.length === 0) {
    console.warn("No Airtable URLs found in HTML - proceeding with original content");
  } else if (newImageUrls.length === 0) {
    console.warn("No Shopify URLs found!");

    // Try alternative extraction methods
    console.log("Attempting alternative URL extraction...");
    try {
      const inputStr = JSON.stringify(currentInput);
      const urlMatches = inputStr.match(/https:\/\/cdn\.shopify\.com[^"]+/g);
      if (urlMatches && urlMatches.length > 0) {
        console.log("Found URLs via string matching:", urlMatches);
        newImageUrls = [...new Set(urlMatches)]; // Remove duplicates
      }
    } catch (e) {
      console.log("Alternative extraction failed:", e.message);
    }

    if (newImageUrls.length === 0) {
      console.warn("No Shopify URLs found - proceeding with original Airtable URLs");
    }
  }

  // --- PERFORM URL REPLACEMENT IF BOTH TYPES OF URLS EXIST ---
  if (finalUrlsToReplace.length > 0 && newImageUrls.length > 0) {
    console.log("Final validation:");
    console.log("- URLs to replace:", finalUrlsToReplace.length);
    console.log("- Shopify URLs available:", newImageUrls.length);

    // Helper function to escape special regex characters
    function escapeRegExp(string) {
      return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    // Create a mapping strategy
    console.log("Creating URL mapping...");
    let urlMapping = {};

    if (finalUrlsToReplace.length <= newImageUrls.length) {
      // We have enough Shopify URLs
      finalUrlsToReplace.forEach((airtableUrl, index) => {
        if (index < newImageUrls.length) {
          urlMapping[airtableUrl] = newImageUrls[index];
          console.log(`Mapping ${index + 1}: ${airtableUrl} -> ${newImageUrls[index]}`);
        }
      });
    } else {
      // More Airtable URLs than Shopify URLs - cycle through Shopify URLs
      console.warn("More Airtable URLs than Shopify URLs - cycling through available URLs");
      finalUrlsToReplace.forEach((airtableUrl, index) => {
        const shopifyUrlIndex = index % newImageUrls.length;
        urlMapping[airtableUrl] = newImageUrls[shopifyUrlIndex];
        console.log(`Mapping ${index + 1}: ${airtableUrl} -> ${newImageUrls[shopifyUrlIndex]} (cycling)`);
      });
    }

    // Perform all replacements using the mapping
    Object.keys(urlMapping).forEach((originalUrl, index) => {
      const newUrl = urlMapping[originalUrl];

      console.log(`Replacing: ${originalUrl} -> ${newUrl}`);
      const regex = new RegExp(escapeRegExp(originalUrl), 'g');
      const beforeReplace = updatedBlogHtml;
      updatedBlogHtml = updatedBlogHtml.replace(regex, newUrl);

      // Check if replacement actually happened
      if (beforeReplace !== updatedBlogHtml) {
        replacementCount++;
        console.log(`✅ Replacement ${index + 1} successful`);
      } else {
        console.log(`❌ Replacement ${index + 1} failed - URL not found in HTML`);
        // Try to find similar URL patterns for debugging
        const similarUrls = blogHtml.match(new RegExp(escapeRegExp(originalUrl.substring(0, 50)), 'g'));
        if (similarUrls) {
          console.log("Found similar URL patterns:", similarUrls);
        }
      }
    });
  }
}

// --- 4. EXTRACT TITLE AND GENERATE HANDLE ---
if (!title) {
  // Fallback: extract title from HTML if not provided in Edit Fields42
  const titleMatch = updatedBlogHtml.match(/<h1[^>]*>(.*?)<\/h1>/i);
  title = titleMatch ? titleMatch[1].replace(/<[^>]*>/g, '') : "Blog Post";
  console.log("Using title from HTML:", title);
} else {
  console.log("Using title from Edit Fields42:", title);
}

// Generate handle if not provided in Edit Fields42
if (!handle) {
  // Generate handle from title
  handle = title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '') // Remove special characters
    .replace(/\s+/g, '-')         // Replace spaces with hyphens
    .replace(/-+/g, '-')          // Replace multiple hyphens with single
    .replace(/^-|-$/g, '');       // Remove leading/trailing hyphens

  console.log("Generated handle from title:", handle);
} else {
  // Clean the provided handle to ensure it's URL-friendly
  handle = handle
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');

  console.log("Using cleaned handle from Edit Fields42:", handle);
}

// --- 5. FORMAT AS SHOPIFY ARTICLE OBJECT ---
const shopifyArticle = {
  article: {
    title: title,
    handle: handle,
    author: "Admin",
    tags: tags,
    body_html: updatedBlogHtml,
    published: false,
    image: {
      src: thumbnailUrl,
      alt: thumbnailAltText
    }
  }
};

if (shouldReplaceUrls) {
  console.log(`Successfully replaced ${replacementCount} out of ${urlsToReplace?.length || 0} URLs`);
} else {
  console.log("No URL replacement performed - used original content");
}

console.log("✅ Shopify article object created successfully!");
console.log("Article summary:", {
  title: shopifyArticle.article.title,
  handle: shopifyArticle.article.handle,
  contentLength: shopifyArticle.article.body_html.length,
  published: shopifyArticle.article.published,
  hasThumbnail: !!shopifyArticle.article.image.src,
  thumbnailUrl: shopifyArticle.article.image.src,
  urlReplacementPerformed: shouldReplaceUrls,
  totalImageReplacements: replacementCount
});

// --- 6. RETURN SHOPIFY ARTICLE OBJECT ---
return shopifyArticle;

