// Function to convert markdown content to Google Docs API requests
function markdownToGoogleDocsRequests(markdown) {
  const requests = [];
  let currentIndex = 1; // Google Docs content starts at index 1

  if (typeof markdown !== 'string') {
    return requests;
  }

  const lines = markdown.split('\n');

  // Helper function for inline parsing and styling
  function parseAndStyleInline(textToParse, startIndex) {
    const segments = [];
    let tempLineForParsing = textToParse;
    const localRequests = [];
    let currentLocalIndex = startIndex;
    let totalCleanTextLength = 0;

    const R_LINK_REGEX_AT_START = /^\[([^\]]+?)\]\s*\(([^)]+?)\)/;

    while (tempLineForParsing.length > 0) {
      let consumed = false;
      let currentSegmentText = "";
      let currentSegmentStyles = {};
      let currentSegmentLinkUrl = null;

      let linkMatch = tempLineForParsing.match(R_LINK_REGEX_AT_START);
      if (linkMatch) {
          currentSegmentText = linkMatch[1];
          currentSegmentLinkUrl = linkMatch[2];
          currentSegmentStyles = {};
          tempLineForParsing = tempLineForParsing.substring(linkMatch[0].length);
          consumed = true;
      }
      else if (tempLineForParsing.startsWith('***') && tempLineForParsing.length >= 6 && tempLineForParsing.substring(3).includes('***')) {
          const endIndex = tempLineForParsing.indexOf('***', 3);
          currentSegmentText = tempLineForParsing.substring(3, endIndex);
          if (currentSegmentText) currentSegmentStyles = { bold: true, italic: true };
          tempLineForParsing = tempLineForParsing.substring(endIndex + 3);
          consumed = true;
      } else if (tempLineForParsing.startsWith('**_') && tempLineForParsing.length >= 5 && tempLineForParsing.substring(3).includes('_**')) {
          const endIndex = tempLineForParsing.indexOf('_**', 3);
          currentSegmentText = tempLineForParsing.substring(3, endIndex);
          if (currentSegmentText) currentSegmentStyles = { bold: true, italic: true };
          tempLineForParsing = tempLineForParsing.substring(endIndex + 3);
          consumed = true;
      } else if (tempLineForParsing.startsWith('_**') && tempLineForParsing.length >= 5 && tempLineForParsing.substring(3).includes('**_')) {
          const endIndex = tempLineForParsing.indexOf('**_', 3);
          currentSegmentText = tempLineForParsing.substring(3, endIndex);
          if (currentSegmentText) currentSegmentStyles = { bold: true, italic: true };
          tempLineForParsing = tempLineForParsing.substring(endIndex + 3);
          consumed = true;
      } else if (tempLineForParsing.startsWith('__*') && tempLineForParsing.length >= 5 && tempLineForParsing.substring(3).includes('*__')) {
          const endIndex = tempLineForParsing.indexOf('*__', 3);
          currentSegmentText = tempLineForParsing.substring(3, endIndex);
          if (currentSegmentText) currentSegmentStyles = { bold: true, italic: true };
          tempLineForParsing = tempLineForParsing.substring(endIndex + 3);
          consumed = true;
      } else if (tempLineForParsing.startsWith('*__') && tempLineForParsing.length >= 5 && tempLineForParsing.substring(3).includes('__*')) {
          const endIndex = tempLineForParsing.indexOf('__*', 3);
          currentSegmentText = tempLineForParsing.substring(3, endIndex);
          if (currentSegmentText) currentSegmentStyles = { bold: true, italic: true };
          tempLineForParsing = tempLineForParsing.substring(endIndex + 3);
          consumed = true;
      }
      else if (tempLineForParsing.startsWith('**')) {
          const marker = '**'; const openingMarkerLength = marker.length;
          const closingMarkerIndex = tempLineForParsing.indexOf(marker, openingMarkerLength);
          if (closingMarkerIndex !== -1) {
              currentSegmentText = tempLineForParsing.substring(openingMarkerLength, closingMarkerIndex);
              if (currentSegmentText) currentSegmentStyles = { bold: true };
              tempLineForParsing = tempLineForParsing.substring(closingMarkerIndex + openingMarkerLength);
              consumed = true;
          }
      } else if (tempLineForParsing.startsWith('__')) {
          const marker = '__'; const openingMarkerLength = marker.length;
          const closingMarkerIndex = tempLineForParsing.indexOf(marker, openingMarkerLength);
          if (closingMarkerIndex !== -1) {
              currentSegmentText = tempLineForParsing.substring(openingMarkerLength, closingMarkerIndex);
              if (currentSegmentText) currentSegmentStyles = { bold: true };
              tempLineForParsing = tempLineForParsing.substring(closingMarkerIndex + openingMarkerLength);
              consumed = true;
          }
      }
      else if (tempLineForParsing.startsWith('*')) {
          const marker = '*'; const openingMarkerLength = marker.length;
          if (tempLineForParsing.length > 1 && tempLineForParsing[1] === '*') { }
          else {
            const closingMarkerIndex = tempLineForParsing.indexOf(marker, openingMarkerLength);
            if (closingMarkerIndex !== -1) {
                currentSegmentText = tempLineForParsing.substring(openingMarkerLength, closingMarkerIndex);
                if (currentSegmentText) currentSegmentStyles = { italic: true };
                tempLineForParsing = tempLineForParsing.substring(closingMarkerIndex + openingMarkerLength);
                consumed = true;
            }
          }
      } else if (tempLineForParsing.startsWith('_')) {
          const marker = '_'; const openingMarkerLength = marker.length;
          if (tempLineForParsing.length > 1 && tempLineForParsing[1] === '_') { }
          else {
            const closingMarkerIndex = tempLineForParsing.indexOf(marker, openingMarkerLength);
            if (closingMarkerIndex !== -1) {
                currentSegmentText = tempLineForParsing.substring(openingMarkerLength, closingMarkerIndex);
                if (currentSegmentText) currentSegmentStyles = { italic: true };
                tempLineForParsing = tempLineForParsing.substring(closingMarkerIndex + openingMarkerLength);
                consumed = true;
            }
          }
      }

      if (consumed) {
          if (currentSegmentText.length > 0) {
              segments.push({ text: currentSegmentText, styles: currentSegmentStyles, linkUrl: currentSegmentLinkUrl });
          }
          continue;
      }

      const markerOrder = ['***', '**_', '_**', '__*', '*__', '**', '__', '*', '_', '['];
      let earliestMarkerPos = -1;
      let foundMarker = "";

      for (const marker of markerOrder) {
          const pos = tempLineForParsing.indexOf(marker);
          if (pos !== -1) {
              if (earliestMarkerPos === -1 || pos < earliestMarkerPos) {
                  earliestMarkerPos = pos;
                  foundMarker = marker;
              } else if (pos === earliestMarkerPos && marker.length > foundMarker.length) {
                  foundMarker = marker;
              }
          }
      }

      if (earliestMarkerPos > 0) {
          currentSegmentText = tempLineForParsing.substring(0, earliestMarkerPos);
          segments.push({ text: currentSegmentText, styles: {}, linkUrl: null });
          tempLineForParsing = tempLineForParsing.substring(earliestMarkerPos);
      } else if (earliestMarkerPos === 0) {
          currentSegmentText = tempLineForParsing.substring(0, foundMarker.length || 1);
          segments.push({ text: currentSegmentText, styles: {}, linkUrl: null });
          tempLineForParsing = tempLineForParsing.substring(currentSegmentText.length);
      } else {
          if (tempLineForParsing.length > 0) {
             segments.push({ text: tempLineForParsing, styles: {}, linkUrl: null });
          }
          tempLineForParsing = "";
      }
    }

    for (const segment of segments) {
        if (segment.text.length === 0) continue;
        localRequests.push({ insertText: { location: { index: currentLocalIndex }, text: segment.text } });

        const textStyleForUpdate = {};
        const fieldsToUpdate = [];

        textStyleForUpdate.bold = !!segment.styles.bold;
        fieldsToUpdate.push('bold');

        textStyleForUpdate.italic = !!segment.styles.italic;
        fieldsToUpdate.push('italic');

        if (segment.linkUrl) {
            textStyleForUpdate.link = { url: segment.linkUrl };
            fieldsToUpdate.push('link');
        } else {
            textStyleForUpdate.foregroundColor = {
                color: { rgbColor: { red: 0.0, green: 0.0, blue: 0.0 } }
            };
            textStyleForUpdate.underline = false;
            textStyleForUpdate.link = null;

            fieldsToUpdate.push('foregroundColor', 'underline', 'link');
        }

        if (fieldsToUpdate.length > 0) {
             localRequests.push({
                updateTextStyle: {
                    range: { startIndex: currentLocalIndex, endIndex: currentLocalIndex + segment.text.length },
                    textStyle: textStyleForUpdate,
                    fields: fieldsToUpdate.sort().join(',')
                }
            });
        }
        currentLocalIndex += segment.text.length;
        totalCleanTextLength += segment.text.length;
    }
    return { requests: localRequests, newIndex: currentLocalIndex, cleanTextLength: totalCleanTextLength };
  }

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.startsWith('# ')) {
      const headerText = line.substring(2);
      const inlineResult = parseAndStyleInline(headerText, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({
        updateParagraphStyle: {
          range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 },
          paragraphStyle: { namedStyleType: 'HEADING_1' },
          fields: 'namedStyleType'
        }
      });
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.startsWith('## ')) {
      const headerText = line.substring(3);
      const inlineResult = parseAndStyleInline(headerText, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({
        updateParagraphStyle: {
          range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 },
          paragraphStyle: { namedStyleType: 'HEADING_2' },
          fields: 'namedStyleType'
        }
      });
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.startsWith('### ')) {
      const headerText = line.substring(4);
      const inlineResult = parseAndStyleInline(headerText, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({
        updateParagraphStyle: {
          range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 },
          paragraphStyle: { namedStyleType: 'HEADING_3' },
          fields: 'namedStyleType'
        }
      });
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.startsWith('#### ')) {
      const headerText = line.substring(5);
      const inlineResult = parseAndStyleInline(headerText, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({
        updateParagraphStyle: {
          range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 },
          paragraphStyle: { namedStyleType: 'HEADING_4' },
          fields: 'namedStyleType'
        }
      });
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.match(/^(\*{3,}|-{3,}|_{3,})$/) && line.trim() === line) {
        requests.push({
            insertText: { location: { index: currentIndex }, text: '\n' }
        });
        requests.push({
            updateParagraphStyle: {
                range: { startIndex: currentIndex, endIndex: currentIndex + 1 },
                paragraphStyle: {
                    borderBottom: { color: { color: { rgbColor: { red: 0.0, green: 0.0, blue: 0.0 } } }, width: { magnitude: 1, unit: 'PT' }, dashStyle: 'SOLID', padding: { magnitude: 0, unit: 'PT' } },
                    indentStart: { magnitude: 0, unit: 'PT' }, indentEnd: { magnitude: 0, unit: 'PT' },
                    spaceAbove: { magnitude: 6, unit: 'PT' }, // Correctly uses spaceAbove
                    spaceBelow: { magnitude: 6, unit: 'PT' }  // Correctly uses spaceBelow
                },
                fields: 'borderBottom,indentStart,indentEnd,spaceAbove,spaceBelow'
            }
        });
        currentIndex += 1;
        requests.push({ insertText: { location: { index: currentIndex }, text: '\n' } });
        currentIndex += 1;
    }
    else if (line.match(/^(\s*)([*\-+])\s(.*)/)) {
      const bulletMatch = line.match(/^(\s*)([*\-+])\s(.*)/);
      const leadingSpaces = bulletMatch[1].length;
      const textContent = bulletMatch[3];
      const nestingLevel = Math.floor(leadingSpaces / 2);

      const inlineResult = parseAndStyleInline(textContent, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({ createParagraphBullets: { range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 }, bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE' } });
      if (nestingLevel > 0) {
          requests.push({ updateParagraphStyle: { range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 }, paragraphStyle: { indentStart: { magnitude: 18 * nestingLevel, unit: 'PT' } }, fields: 'indentStart' } });
      }
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.match(/^(\s*)(\d+)\.\s(.*)/)) {
      const numberedListMatch = line.match(/^(\s*)(\d+)\.\s(.*)/);
      const leadingSpaces = numberedListMatch[1].length;
      const textContent = numberedListMatch[3];
      const nestingLevel = Math.floor(leadingSpaces / 2);

      const inlineResult = parseAndStyleInline(textContent, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      requests.push({ createParagraphBullets: { range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 }, bulletPreset: 'NUMBERED_DECIMAL_ALPHA_ROMAN' } });
      if (nestingLevel > 0) {
        requests.push({ updateParagraphStyle: { range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 }, paragraphStyle: { indentStart: { magnitude: 18 * nestingLevel, unit: 'PT' } }, fields: 'indentStart' } });
      }
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.startsWith('> ')) {
      let currentLine = line;
      let indentLevel = 0;
      let text = '';
      while(currentLine.startsWith('>')) {
        indentLevel++;
        currentLine = currentLine.substring(currentLine[1] === ' ' ? 2 : 1).trimStart();
      }
      text = currentLine;

      const inlineResult = parseAndStyleInline(text, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      if (indentLevel > 0) {
        requests.push({
          updateParagraphStyle: {
            range: { startIndex: currentIndex, endIndex: inlineResult.newIndex + 1 },
            paragraphStyle: {
              indentStart: { magnitude: 18 * indentLevel, unit: 'PT' },
              borderLeft: { width: { magnitude: 2, unit: 'PT' }, padding: { magnitude: 4, unit: 'PT' }, dashStyle: 'SOLID', color: { color: { rgbColor: { red: 0.8, green: 0.8, blue: 0.8 } } } }
            },
            fields: 'indentStart,borderLeft'
          }
        });
      }
      currentIndex = inlineResult.newIndex + 1;
    }
    // Handle code blocks
    else if (line.startsWith('```')) {
      let codeContent = '';
      let j = i + 1;
      while (j < lines.length && !lines[j].startsWith('```')) {
        codeContent += lines[j] + '\n';
        j++;
      }
      if (codeContent.endsWith('\n')) {
          codeContent = codeContent.slice(0, -1);
      }
      if (codeContent.length > 0) {
          requests.push({ insertText: { location: { index: currentIndex }, text: codeContent } });
          // Apply text style for code
          requests.push({
            updateTextStyle: {
              range: { startIndex: currentIndex, endIndex: currentIndex + codeContent.length },
              textStyle: { weightedFontFamily: { fontFamily: 'Consolas', weight: 400 }, fontSize: { magnitude: 10, unit: 'PT' }, bold: false, italic: false },
              fields: 'weightedFontFamily,fontSize,bold,italic'
            }
          });
          // Apply paragraph style for code block
           requests.push({
            updateParagraphStyle: {
              range: { startIndex: currentIndex, endIndex: currentIndex + codeContent.length }, // Range covers the inserted code content
              paragraphStyle: {
                shading: { backgroundColor: { color: { rgbColor: { red: 0.95, green: 0.95, blue: 0.95 } } } },
                lineSpacing: 100, // Assumed to be a percentage
                spaceAbove: {magnitude: 0, unit: 'PT'}, // CORRECTED from spaceBefore
                spaceBelow: {magnitude: 0, unit: 'PT'}, // CORRECTED from spaceAfter
                keepLinesTogether: true,
              },
              // CORRECTED fields to match corrected property names
              fields: 'shading,lineSpacing,spaceAbove,spaceBelow,keepLinesTogether'
            }
          });
          currentIndex += codeContent.length;
      }
      requests.push({ insertText: { location: { index: currentIndex }, text: '\n' } });
      currentIndex += 1;
      i = j;
    }
    else if (line.includes('|') && line.trim().startsWith('|') && line.trim().endsWith('|')) {
      const inlineResult = parseAndStyleInline(line, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({
        updateTextStyle: {
          range: { startIndex: currentIndex, endIndex: inlineResult.newIndex },
          textStyle: {
            weightedFontFamily: { fontFamily: 'Courier New', weight: 400 }
          },
          fields: 'weightedFontFamily'
        }
      });
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      currentIndex = inlineResult.newIndex + 1;
    }
    else if (line.trim() === '') {
      requests.push({ insertText: { location: { index: currentIndex }, text: '\n' } });
      currentIndex += 1;
    }
    else {
      const inlineResult = parseAndStyleInline(line, currentIndex);
      requests.push(...inlineResult.requests);
      requests.push({ insertText: { location: { index: inlineResult.newIndex }, text: '\n' } });
      currentIndex = inlineResult.newIndex + 1;
    }
  }
  return requests;
}

// Main n8n Code Node execution
try {
  const markdownContent = $('Edit Fields49').first().json.Content;

  if (markdownContent === null || typeof markdownContent === 'undefined') {
    // @ts-ignore
    return {
      json: {
        requestString: JSON.stringify({ requests: [] }),
        requestCount: 0,
        status: "success_no_content",
        message: "Markdown content is null or undefined."
      }
    };
  }

  if (typeof markdownContent !== 'string') {
    throw new Error("Markdown content is not a string. Found type: " + typeof markdownContent);
  }

  const requests = markdownToGoogleDocsRequests(markdownContent);
  const requestBody = { requests: requests };

  // @ts-ignore
  return {
    json: {
      requestString: JSON.stringify(requestBody),
      requestCount: requests.length,
      status: "success"
    }
  };

} catch (error) {
  console.error("Error in Markdown to Google Docs conversion:", error.stack);
  // @ts-ignore
  return {
    json: {
      error: error.message,
      stack: error.stack,
      status: "error"
    }
  };
}

